mapper.insert:
INSERT INTO user_mute_history (
    user_id, operator_id, action, reason,
    mute_duration, mute_end_time, unmute_type
) VALUES (
    #{userId}, #{operatorId}, #{action}, #{reason},
    #{muteDuration}, #{muteEndTime}, #{unmuteType}
)

mapper.select:
SELECT h.*, op.username AS operator_name
FROM user_mute_history h
JOIN users op ON op.id = h.operator_id
WHERE h.user_id = #{userId}
ORDER BY h.created_at DESC
LIMIT #{offset}, #{limit}
